SELECT count(*) FROM cast_info, name, aka_name, title, movie_companies, char_name, kind_type, role_type, company_name WHERE cast_info.person_id = name.id AND aka_name.person_id = name.id AND cast_info.movie_id = title.id AND movie_companies.movie_id = title.id AND cast_info.person_role_id = char_name.id AND title.kind_id = kind_type.id AND cast_info.role_id = role_type.id AND movie_companies.company_id = company_name.id;